import React, { useEffect, useState } from "react";
import SkeletonRows from "../SkeletonRows";
import type { IAccordionProps } from "@lmb-it/kitsconcerto-types";
import { Accordion, AccordionTab } from "primereact/accordion";
import {Box, Heading, Text} from "../../_compat";

const CustomAccordion= ({
                                                  accordionTitle,
                                                  accordionItems,
                                                  isLoading,
                                                  allOpenedByDefault,
                                                  localProps,
                                              }:IAccordionProps) => {
    const [activeIndex, setActiveIndex] = useState<number | number[]>(
        localProps?.multiple ? [0] : 0,
    );

    useEffect(() => {
        if (allOpenedByDefault) {
            setActiveIndex(
                Array.from({ length: accordionItems?.length ?? 0 }, (_, i) => i),
            );
        }
    }, [allOpenedByDefault]);

    return (
        <Box
            className={"backgrounds base-bg"}
            borderRadius={8}
            overflow="hidden"
            w={"100%"}
        >
            {!!accordionTitle && (
                <Heading
                    as={"h2"}
                    p={4}
                    fontSize={"lg"}
                    className={"backgrounds header-bg"}
                >
                    {accordionTitle}
                </Heading>
            )}
            {isLoading ? (
                <SkeletonRows rowsLength={accordionItems?.length ?? 0} />
            ) : (
                <Accordion
                    {...localProps}
                    activeIndex={activeIndex}
                    multiple
                    onTabChange={(e) => setActiveIndex(e.index)}
                >
                    {accordionItems &&
                        accordionItems.map(({ button, panel, onToggle }, i) => (
                            <AccordionTab key={i} header={button}>
                                {panel}
                            </AccordionTab>
                        ))}
                </Accordion>
            )}
        </Box>
    );
};

export default CustomAccordion;
